private List<ErrorSintactico> erroresSintacticos = new ArrayList<>();

public void syntax_error(Symbol s) {
    String lexema = (s != null && s.value != null)
            ? s.value.toString()
            : (s != null ? symbl_name_from_id(s.sym) : "desconocido");

    int linea   = (s != null) ? s.left  : 0;
    int columna = (s != null) ? s.right : 0;

    StringBuilder descripcion = new StringBuilder();
    descripcion.append("Se encontró '").append(lexema).append("'. ");

    if (expected_token_ids().isEmpty()) {
        descripcion.append("No se esperaba ningún símbolo.");
    } else {
        descripcion.append("Se esperaba: ");
        for (Integer id : expected_token_ids()) {
            String nombre = symbl_name_from_id(id);
            if (!nombre.equals("error")) {
                descripcion.append(nombre).append(", ");
            }
        }
        if (descripcion.toString().endsWith(", ")) {
            descripcion.setLength(descripcion.length() - 2);
        }
    }

    erroresSintacticos.add(new ErrorSintactico(
        lexema,
        linea,
        columna,
        descripcion.toString()
    ));
}

public void unrecovered_syntax_error(Symbol s) {
    String lexema = (s != null && s.value != null)
            ? s.value.toString()
            : (s != null ? symbl_name_from_id(s.sym) : "EOF");

    erroresSintacticos.add(new ErrorSintactico(
        lexema,
        s != null ? s.left  : 0,
        s != null ? s.right : 0,
        "Error irrecuperable cerca de '" + lexema + "'"
    ));
}

    public List<ErrorSintactico> getErroresSintacticos(){
        return erroresSintacticos;
    }



